import{c as a,Q as l,j as e,m as n}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"Serverless 是什么:函数、冷启动、触发器、限制","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/13-Serverless是什么.md","filePath":"cloudBasicsLearning/13-Serverless是什么.md","lastUpdated":1779015580000}'),p={name:"cloudBasicsLearning/13-Serverless是什么.md"};function i(t,s,r,o,c,d){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="serverless-是什么-函数、冷启动、触发器、限制" tabindex="-1">Serverless 是什么:函数、冷启动、触发器、限制 <a class="header-anchor" href="#serverless-是什么-函数、冷启动、触发器、限制" aria-label="Permalink to &quot;Serverless 是什么:函数、冷启动、触发器、限制&quot;">​</a></h1><blockquote><p>一句话先记住:Serverless 不是没有服务器,而是你不直接管理服务器,平台按请求、事件或运行时间帮你启动和调度计算资源。</p></blockquote><p>Serverless 最吸引人的地方是简单:写一段函数,绑定一个 HTTP 路由、定时任务、队列消息或对象存储事件,平台就能运行它。你不需要先买服务器,不用配置进程守护,不用手动扩容。</p><p>但 Serverless 也最容易被神化。它适合事件驱动、短任务、低运维、弹性流量,不适合所有后端。它会把服务器管理问题换成平台限制、冷启动、超时、并发、连接数、可观测性和成本模型问题。</p><hr><h2 id="一、一句话解释" tabindex="-1">一、一句话解释 <a class="header-anchor" href="#一、一句话解释" aria-label="Permalink to &quot;一、一句话解释&quot;">​</a></h2><p>Serverless 是一种运行模型:你提交函数或轻量服务,平台负责调度运行环境,按调用、耗时、资源用量或事件次数计费。</p><p>常见形态包括:</p><ul><li>Function as a Service,比如 HTTP 函数、API Routes、边缘函数</li><li>Serverless 容器,比如按请求启动的容器服务</li><li>Serverless 数据库或队列,比如自动扩缩容的托管后端组件</li><li>静态托管里的构建函数、图片处理函数、边缘中间件</li></ul><p>最容易误解的是&quot;Serverless 等于不用管运维&quot;。更准确的说法是:你不用管理机器,但仍然要管理代码、依赖、权限、数据库连接、超时、重试、日志、告警和账单。</p><p>可以粗略理解成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统服务器:</span></span>
<span class="line"><span>  我先租一台机器,让程序一直运行,有没有请求都付钱</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Serverless:</span></span>
<span class="line"><span>  我提交一段可被触发的代码,有事件时平台调度它运行,通常按使用量付钱</span></span></code></pre></div><hr><h2 id="二、放在系统哪里" tabindex="-1">二、放在系统哪里 <a class="header-anchor" href="#二、放在系统哪里" aria-label="Permalink to &quot;二、放在系统哪里&quot;">​</a></h2><p>Serverless 位于计算层,但它通常和网关、事件源、托管存储紧密绑定。</p><p>HTTP 场景的链路可能是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; DNS</span></span>
<span class="line"><span>  -&gt; CDN / WAF</span></span>
<span class="line"><span>  -&gt; API Gateway / 平台路由</span></span>
<span class="line"><span>  -&gt; Serverless Function</span></span>
<span class="line"><span>  -&gt; 数据库 / 缓存 / 对象存储 / 第三方 API</span></span></code></pre></div><p>事件驱动场景的链路可能是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户上传图片到对象存储</span></span>
<span class="line"><span>  -&gt; 对象存储产生事件</span></span>
<span class="line"><span>  -&gt; 触发 Serverless Function</span></span>
<span class="line"><span>  -&gt; 函数压缩图片 / 写数据库 / 发消息</span></span></code></pre></div><p>Serverless 很适合把&quot;有事件才需要运行&quot;的逻辑拆出来:</p><ul><li>表单提交</li><li>Webhook 回调</li><li>图片压缩</li><li>定时清理</li><li>订单状态同步</li><li>邮件发送</li><li>低频后台任务</li><li>轻量 API</li></ul><p>但它不天然适合长连接和持续运行:</p><ul><li>WebSocket 长连接</li><li>长时间视频处理</li><li>大型爬虫常驻调度</li><li>高并发低延迟数据库代理</li><li>需要本地磁盘长期保存状态的服务</li></ul><p>有些平台提供了边缘函数,运行在更靠近用户的节点上。它适合鉴权、重定向、A/B 测试、请求改写、轻量缓存判断等短逻辑。边缘函数通常运行限制更严格,不适合把完整后端都塞进去。</p><hr><h2 id="三、常见套餐和使用限制" tabindex="-1">三、常见套餐和使用限制 <a class="header-anchor" href="#三、常见套餐和使用限制" aria-label="Permalink to &quot;三、常见套餐和使用限制&quot;">​</a></h2><p>Serverless 的套餐限制通常按多个维度同时计算:</p><ul><li>调用次数</li><li>执行时间</li><li>CPU / 内存</li><li>最大超时时间</li><li>并发数</li><li>请求体大小和响应大小</li><li>冷启动延迟</li><li>构建分钟</li><li>日志保留</li><li>出站流量</li><li>区域和边缘节点</li><li>环境变量数量和大小</li><li>定时任务数量</li></ul><p>它的免费额度看起来很慷慨,但要注意每个维度是独立限制。一个项目可能调用次数没超,但执行时间超了;执行时间没超,但出站流量超了;流量没超,但日志保留或构建分钟开始收费。</p><p>Serverless 的几个典型坑:</p><p><strong>1. 冷启动</strong></p><p>函数一段时间没有请求后,平台可能回收运行环境。下一次请求需要重新初始化运行时、加载依赖、建立连接,延迟会变高。对后台任务影响不大,对登录、支付、首屏 API 这类路径可能影响体验。</p><p><strong>2. 超时</strong></p><p>Serverless 平台通常有最大执行时间。短函数没问题,但批量导入、视频处理、大模型调用、慢第三方 API,都可能被平台强制终止。</p><p><strong>3. 数据库连接</strong></p><p>传统服务器可以复用少量长连接。Serverless 高并发时可能瞬间启动很多函数实例,每个实例都连接数据库,很容易打满数据库连接数。很多&quot;Serverless + Postgres&quot;的问题,根源不是函数,而是连接池和并发控制。</p><p><strong>4. 重试和重复执行</strong></p><p>事件触发函数失败后,平台可能自动重试。你的代码必须考虑幂等性。比如扣款、发券、发邮件、写订单状态,不能因为重试执行两次就产生错误结果。</p><p><strong>5. 账单不可见</strong></p><p>Serverless 的成本和流量形态高度相关。平时几乎免费,突然被爬虫、Webhook 风暴、错误重试、缓存失效打穿时,调用次数和执行时间会一起上涨。</p><hr><h2 id="四、小团队建议" tabindex="-1">四、小团队建议 <a class="header-anchor" href="#四、小团队建议" aria-label="Permalink to &quot;四、小团队建议&quot;">​</a></h2><p>什么时候 Serverless 很适合?</p><ul><li>流量不稳定,有明显波峰波谷</li><li>低频后台任务,没必要常驻一台服务器</li><li>Webhook、定时任务、图片处理、轻量 API</li><li>前端项目需要少量后端能力</li><li>团队不想维护服务器</li><li>业务还在验证期,希望按使用量起步</li></ul><p>什么时候要谨慎?</p><ul><li>核心接口对延迟非常敏感</li><li>请求需要运行很久</li><li>需要大量数据库长连接</li><li>需要复杂本地状态</li><li>需要稳定低成本承载持续高流量</li><li>平台限制会影响业务逻辑</li><li>团队没有做预算告警和调用监控</li></ul><p>Serverless 不一定比服务器便宜。低流量、波动流量、事件驱动场景,它通常很省。持续高流量、每个请求都要运行较久、出站流量大、日志多的场景,固定服务器或容器平台可能更可控。</p><p>一个保守架构是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端:</span></span>
<span class="line"><span>  静态托管 / CDN</span></span>
<span class="line"><span></span></span>
<span class="line"><span>轻量 API:</span></span>
<span class="line"><span>  Serverless Function</span></span>
<span class="line"><span></span></span>
<span class="line"><span>持久数据:</span></span>
<span class="line"><span>  托管数据库 / 对象存储</span></span>
<span class="line"><span></span></span>
<span class="line"><span>异步任务:</span></span>
<span class="line"><span>  队列 + Serverless Function</span></span>
<span class="line"><span></span></span>
<span class="line"><span>高频核心后端:</span></span>
<span class="line"><span>  服务器 / 容器 / PaaS,视规模而定</span></span></code></pre></div><p>最低限度的护栏:</p><ul><li>设置预算告警和用量告警</li><li>给函数加超时和错误日志</li><li>对外部 API 调用设置超时</li><li>数据库使用连接池或平台推荐的连接方式</li><li>关键写操作保证幂等</li><li>对公开接口做限流和鉴权</li><li>不要把大文件处理和长任务硬塞进短超时函数</li><li>确认免费额度超出后是停用、限流还是自动计费</li></ul><p>Serverless 最适合的是&quot;把不值得常驻服务器的计算交给平台&quot;。它不是后端架构的终点,也不是成本优化的保证。</p><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p>Serverless 让你少管服务器,按事件和请求运行代码,非常适合短任务、轻量 API 和波动流量;但它有冷启动、超时、并发、连接数和计费边界,小团队应该把它当成一种部署选择,不是万能后端。</p>`,55)])])}const v=a(p,[["render",i]]);export{h as __pageData,v as default};
